('2016300004001000001', '221', '2026年国家奖学金评选通知', '最高荣誉，等你申请', '# 国家奖学金评选\n\n各位同学：\n\n2026年国家奖学金评选工作正式启动。\n\n## 评选条件\n\n1. 二年级及以上在校本科生\n2. 学习成绩排名位于专业前10%\n3. 综合素质测评优秀\n4. 无违纪记录\n\n## 奖励标准\n\n每人每年8000元\n\n## 申请材料\n\n1. 国家奖学金申请表\n2. 成绩单\n3. 获奖证书复印件\n4. 个人事迹材料\n\n## 截止时间\n\n2026年9月30日\n\n请符合条件的同学积极申请！', NULL, '2016105578056781824', 'admin', 456, 0, 0, 0, 1, 1, '2026-05-13 09:00:00', '2016105578056781824', '2026-05-13 09:00:00', '', '2026-05-13 09:00:00', 0),

('2016300004001000002', '221', '国家励志奖学金申请指南', '励志成才，自强不息', '# 励志奖学金\n\n## 资助对象\n\n家庭经济困难、品学兼优的在校本科生。\n\n## 申请条件\n\n1. 经学校认定的家庭经济困难学生\n2. 学习成绩排名位于专业前30%\n3. 生活俭朴，无不良消费习惯\n4. 积极参加公益活动\n\n## 奖励标准\n\n每人每年5000元\n\n## 申请流程\n\n1. 填写申请表\n2. 提交家庭经济情况证明\n3. 学院初审\n4. 学校复审\n5. 公示名单\n\n## 注意事项\n\n申请材料需真实有效，弄虚作假者取消资格。', NULL, '2016105578056781824', 'admin', 234, 0, 0, 0, 0, 1, '2026-05-14 10:00:00', '2016105578056781824', '2026-05-14 10:00:00', '', '2026-05-14 10:00:00', 0),

('2016300004001000003', '221', '校级奖学金评定办法', '激励优秀，全面发展', '# 校级奖学金\n\n## 奖项设置\n\n### 一等奖学金\n- 金额：3000元/年\n- 比例：专业前5%\n\n### 二等奖学金\n- 金额：2000元/年\n- 比例：专业前15%\n\n### 三等奖学金\n- 金额：1000元/年\n- 比例：专业前30%\n\n## 评定依据\n\n1. 学业成绩（60%）\n2. 综合素质（30%）\n3. 创新实践（10%）\n\n## 发放时间\n\n每学期开学后一个月内发放。', NULL, '2016105578056781824', 'admin', 189, 0, 0, 0, 0, 1, '2026-05-15 11:00:00', '2016105578056781824', '2026-05-15 11:00:00', '', '2026-05-15 11:00:00', 0),

('2016300004001000004', '221', '专项奖学金申请通知', '特色奖励，多元发展', '# 专项奖学金\n\n## 奖项类别\n\n### 学习进步奖\n奖励学习成绩显著进步的学生。\n\n### 创新创业奖\n奖励在创新创业方面表现突出的学生。\n\n### 社会工作奖\n奖励在学生工作中表现优秀的学生干部。\n\n### 文体活动奖\n奖励在文体活动中取得优异成绩的学生。\n\n## 申请条件\n\n1. 在相应领域有突出表现\n2. 无违纪记录\n3. 学习成绩合格\n\n## 奖励金额\n\n500-2000元不等\n\n欢迎符合条件的同学申请！', NULL, '2016105578056781824', 'admin', 145, 0, 0, 0, 0, 1, '2026-05-16 09:00:00', '2016105578056781824', '2026-05-16 09:00:00', '', '2026-05-16 09:00:00', 0),

