('2016300004008000001', '612', '宿舍安全检查通知', '安全第一，防患未然', '# 安全检查\n\n为保障宿舍安全，学校将开展宿舍安全检查。\n\n## 检查时间\n\n2026年5月20日 9:00-17:00\n\n## 检查内容\n\n1. 违规电器\n2. 私拉电线\n3. 易燃物品\n4. 消防通道\n5. 卫生状况\n\n## 违规处理\n\n- 没收违规物品\n- 通报批评\n- 情节严重者给予处分\n\n## 配合要求\n\n1. 提前自查自纠\n2. 配合检查工作\n3. 保持宿舍整洁\n\n## 安全提醒\n\n宿舍安全人人有责，请大家自觉遵守规定。', NULL, '2016105578056781824', 'admin', 234, 0, 0, 0, 0, 1, '2026-05-13 10:00:00', '2016105578056781824', '2026-05-13 10:00:00', '', '2026-05-13 10:00:00', 0),

('2016300004008000002', '612', '宿舍门禁系统升级通知', '智能管理，安全升级', '# 门禁升级\n\n宿舍门禁系统将进行升级改造。\n\n## 升级时间\n\n2026年5月18日-20日\n\n## 升级内容\n\n1. 人脸识别功能\n2. 访客登记系统\n3. 出入记录查询\n\n## 注意事项\n\n1. 升级期间使用校园卡刷卡进入\n2. 请配合采集人脸信息\n3. 采集时间：5月15日-17日\n4. 采集地点：各宿舍楼大厅\n\n## 新功能\n\n- 刷脸进门\n- 临时访客预约\n- 晚归记录提醒\n\n请同学们配合升级工作。', NULL, '2016105578056781824', 'admin', 178, 0, 0, 0, 0, 1, '2026-05-14 11:00:00', '2016105578056781824', '2026-05-14 11:00:00', '', '2026-05-14 11:00:00', 0),

('2016300004008000003', '612', '文明宿舍评选通知', '共建文明宿舍', '# 文明宿舍评选\n\n2026年春季学期文明宿舍评选开始。\n\n## 评选标准\n\n### 卫生方面（40分）\n- 地面干净整洁\n- 物品摆放有序\n- 床铺整齐\n\n### 安全方面（30分）\n- 无违规电器\n- 无私拉电线\n- 消防通道畅通\n\n### 文化方面（30分）\n- 宿舍氛围好\n- 团结互助\n- 遵守纪律\n\n## 奖励措施\n\n- 一等奖：奖金500元+流动红旗\n- 二等奖：奖金300元\n- 三等奖：奖金100元\n\n## 报名方式\n\n各楼栋宿管处报名。\n\n截止时间：5月25日', NULL, '2016105578056781824', 'admin', 145, 0, 0, 0, 0, 1, '2026-05-15 09:00:00', '2016105578056781824', '2026-05-15 09:00:00', '', '2026-05-15 09:00:00', 0),

('2016300004008000004', '612', '宿舍报修流程说明', '快速报修，及时解决', '# 报修流程\n\n## 报修范围\n\n- 水电设施\n- 门窗家具\n- 空调热水器\n- 网络设备\n\n## 报修方式\n\n### 线上报修\n1. 登录校园智通平台\n2. 进入"宿舍报修"模块\n3. 填写报修信息\n4. 提交申请\n\n### 线下报修\n到宿管处填写报修单。\n\n## 处理时限\n\n- 紧急维修：24小时内\n- 一般维修：3个工作日内\n- 大型维修：7个工作日内\n\n## 注意事项\n\n1. 描述问题要准确\n2. 保持电话畅通\n3. 配合维修人员\n\n如有问题请联系宿管。', NULL, '2016105578056781824', 'admin', 89, 0, 0, 0, 0, 1, '2026-05-16 10:00:00', '2016105578056781824', '2026-05-16 10:00:00', '', '2026-05-16 10:00:00', 0),

('2016300004008000005', '612', '暑假留校住宿申请通知', '留校申请指南', '# 留校申请\n\n暑假期间需要留校的同学请提前申请。\n\n## 申请条件\n\n1. 因学习、科研需要\n2. 家庭经济困难学生\n3. 参加学校活动\n\n## 申请流程\n\n1. 填写留校申请表\n2. 导师/辅导员签字\n3. 学院审批\n4. 后勤备案\n\n## 申请时间\n\n2026年6月1日-20日\n\n## 留校安排\n\n- 集中住宿\n- 开放部分食堂\n- 自习室开放\n\n## 注意事项\n\n1. 遵守留校规定\n2. 注意人身安全\n3. 按时归寝\n\n请有需要的同学及时申请。', NULL, '2016105578056781824', 'admin', 67, 0, 0, 0, 0, 1, '2026-05-17 11:00:00', '2016105578056781824', '2026-05-17 11:00:00', '', '2026-05-17 11:00:00', 0),

