('2016300004011000001', '81', '学费缴纳通知', '按时缴费，顺利完成注册', '# 学费缴纳\n\n2026年秋季学期学费缴纳工作即将开始。\n\n## 缴费时间\n\n2026年8月20日-9月10日\n\n## 缴费标准\n\n### 本科生\n- 普通专业：5000元/年\n- 艺术类专业：10000元/年\n- 中外合作专业：30000元/年\n\n### 研究生\n- 学术型：8000元/年\n- 专业型：10000-20000元/年\n\n## 缴费方式\n\n1. 银行代扣\n2. 网上缴费\n3. 现场缴费\n\n## 注意事项\n\n1. 按时缴费，逾期将影响注册\n2. 缴费后保留凭证\n3. 申请助学贷款的同学按贷款流程办理\n\n如有疑问请联系财务处。', NULL, '2016105578056781824', 'admin', 234, 0, 0, 0, 0, 1, '2026-05-13 09:00:00', '2016105578056781824', '2026-05-13 09:00:00', '', '2026-05-13 09:00:00', 0),

('2016300004011000002', '81', '住宿费缴纳说明', '住宿缴费指南', '# 住宿费缴纳\n\n## 收费标准\n\n### 普通宿舍\n- 4人间：1200元/年\n- 6人间：800元/年\n\n### 公寓式宿舍\n- 单人间：3000元/年\n- 双人间：2000元/年\n\n## 缴费方式\n\n与学费一并缴纳。\n\n## 退费规定\n\n- 开学两周内退宿：全额退还\n- 开学两周后退宿：按月折算退还\n\n## 换宿费用\n\n换宿不产生额外费用，但需重新核定住宿费差额。\n\n## 注意事项\n\n住宿费按学年缴纳，中途退宿需办理相关手续。', NULL, '2016105578056781824', 'admin', 178, 0, 0, 0, 0, 1, '2026-05-14 10:00:00', '2016105578056781824', '2026-05-14 10:00:00', '', '2026-05-14 10:00:00', 0),

('2016300004011000003', '81', '学生财务报销流程说明', '规范报销，提高效率', '# 财务报销\n\n## 报销范围\n\n1. 学生活动经费\n2. 科研项目经费\n3. 竞赛参赛费用\n4. 其他经批准的费用\n\n## 报销流程\n\n1. 准备原始票据\n2. 填写报销单\n3. 导师/辅导员签字\n4. 学院审批\n5. 财务处审核\n6. 领取报销款\n\n## 所需材料\n\n- 正规发票\n- 活动审批表\n- 费用明细清单\n\n## 报销时间\n\n每周二、周四 9:00-11:30, 14:00-17:00\n\n## 注意事项\n\n发票抬头必须为学校全称。', NULL, '2016105578056781824', 'admin', 145, 0, 0, 0, 0, 1, '2026-05-15 11:00:00', '2016105578056781824', '2026-05-15 11:00:00', '', '2026-05-15 11:00:00', 0),

('2016300004011000004', '81', '助学贷款办理通知', '助学贷款，助力求学', '# 助学贷款\n\n## 贷款类型\n\n### 生源地信用助学贷款\n- 在户籍所在地办理\n- 最高额度12000元/年\n\n### 校园地助学贷款\n- 在学校办理\n- 最高额度12000元/年\n\n## 申请条件\n\n1. 家庭经济困难\n2. 诚实守信\n3. 学习刻苦\n\n## 申请材料\n\n1. 贷款申请表\n2. 家庭经济情况证明\n3. 身份证、学生证复印件\n\n## 办理时间\n\n- 生源地贷款：暑假期间\n- 校园地贷款：开学后一个月内\n\n## 还款方式\n\n毕业后开始还款，最长还款期限20年。', NULL, '2016105578056781824', 'admin', 89, 0, 0, 0, 0, 1, '2026-05-16 09:00:00', '2016105578056781824', '2026-05-16 09:00:00', '', '2026-05-16 09:00:00', 0),

('2016300004011000005', '81', '财务处办公时间调整通知', '服务时间更新', '# 办公时间调整\n\n财务处办公时间调整如下：\n\n## 调整后时间\n\n- 周一至周五：8:30-11:30, 14:00-17:00\n- 周三下午：内部学习，不对外办公\n\n## 办公地点\n\n行政楼一楼财务处\n\n## 业务窗口\n\n- 窗口1-2：学费缴纳\n- 窗口3-4：报销业务\n- 窗口5：助学贷款\n\n## 生效时间\n\n2026年5月20日起\n\n## 联系方式\n\n电话：0123-8888890\n\n请同学们合理安排办理时间。', NULL, '2016105578056781824', 'admin', 67, 0, 0, 0, 0, 1, '2026-05-17 10:00:00', '2016105578056781824', '2026-05-17 10:00:00', '', '2026-05-17 10:00:00', 0),

